module top_module(
    input not_x,
    input y,
    output m
);
    assign m = not_x | ~y;
endmodule

module L(
    input not_x,
    input y,
    output m
);
    assign m = not_x | ~y;
endmodule

module top_module(
    input not_x,
    input y,
    output m
);
    wire k1_out, k2_out, l1_out, l2_out;
    wire xor_out, and_out;

    K k1(.not_x(not_x), .y(y), .m(k1_out));
    K k2(.not_x(not_x), .y(y), .m(k2_out));
    L l1(.not_x(not_x), .y(y), .m(l1_out));
    L l2(.not_x(not_x), .y(y), .m(l2_out));

    assign xor_out = k1_out ^ l1_out;
    assign and_out = k2_out & l2_out;

    assign m = xor_out | and_out;
endmodule
